// Module avatars kart — VERSION ILLUSTRÉE (jeu /avatars/SVG).
// Remplace le générateur paramétrique précédent. Chaque kart reçoit une des 24 vignettes
// circulaires dessinées à la main (fond dégradé, anneau + touches de couleur, pilote dans
// son kart). Le NUMÉRO affiché sur la plaque est injecté dynamiquement (= numéro de kart),
// et le schéma (0-23) est déduit du numéro de kart, exactement comme avant :
//   kart 1 -> variante 01, kart 2 -> 02, ... kart 24 -> 24, kart 25 -> 01, etc.
//
// API IDENTIQUE à l'ancienne (schemeForKart, schemeColors, kartAvatarSVG, kartAvatarDataURL)
// -> aucun appelant (public-results.js, settings.js, admin.html, exports PDF) à modifier.
//
// Les 24 dessins sont embarqués (badge de coin retiré, plaque numéro dynamique). Les
// identifiants internes (dégradés, filtres, classes CSS) sont suffixés à CHAQUE rendu pour
// éviter toute collision quand plusieurs avatars coexistent sur une même page.

export const AVATAR_SCHEME_COUNT = 24;

// Schéma (0-23) déterministe à partir du numéro de kart. Même kart = même avatar.
export function schemeForKart(kartNumber) {
  const n = Number(kartNumber);
  if (!Number.isFinite(n)) return 0;
  return ((Math.round(n) - 1) % AVATAR_SCHEME_COUNT + AVATAR_SCHEME_COUNT) % AVATAR_SCHEME_COUNT;
}

// Conservé pour compatibilité : renvoie une paire de teintes indicative pour un schéma.
// (Les vignettes n'utilisent plus ces valeurs, mais l'export reste disponible.)
export function schemeColors(index) {
  const i = ((index % AVATAR_SCHEME_COUNT) + AVATAR_SCHEME_COUNT) % AVATAR_SCHEME_COUNT;
  const h = (i * 15) % 360;
  return { helmet: `hsl(${h} 85% 56%)`, body: `hsl(${(h + 165) % 360} 78% 52%)` };
}

