let __uid = 0;

// Dessin SVG (chaîne) de l'avatar d'un kart.
//   kartNumber : numéro affiché sur la plaque (null/'' -> pas de numéro)
//   opts.scheme : force un schéma 0-23 (sinon déduit du numéro de kart)
//   opts.size   : largeur/hauteur en px (défaut : 100% du conteneur)
//   opts.title  : texte accessible (<title>)
export function kartAvatarSVG(kartNumber, opts = {}) {
  const idx = opts.scheme != null
    ? ((Math.round(opts.scheme) % AVATAR_SCHEME_COUNT) + AVATAR_SCHEME_COUNT) % AVATAR_SCHEME_COUNT
    : schemeForKart(kartNumber);
  const num = (kartNumber == null || kartNumber === '') ? '' : String(kartNumber);
  const fs = num.length >= 3 ? 10 : num.length === 2 ? 13 : 15;
  const plate = num
    ? `<text x="74" y="87" text-anchor="middle" dominant-baseline="middle" font-family="Arial,Helvetica,sans-serif" font-weight="900" font-size="${fs}" fill="#fff">${num}</text>`
    : '';
  const dims = opts.size ? `width="${opts.size}" height="${opts.size}"` : 'width="100%" height="100%"';
  const title = opts.title ? `<title>${opts.title}</title>` : '';
  const sfx = 'a' + (++__uid).toString(36);
  return TEMPLATES[idx]
    .split('__SFX__').join(sfx)
    .replace('{{DIMS}}', dims)
    .replace('{{TITLE}}', title)
    .replace('{{NUM}}', num)
    .replace('{{PLATE}}', plate);
}

// Même dessin encodé en data URL — pour un <img> (exports PDF via html2canvas).
export function kartAvatarDataURL(kartNumber, opts = {}) {
  const svg = kartAvatarSVG(kartNumber, { ...opts, size: opts.size || 100 });
  return 'data:image/svg+xml,' + encodeURIComponent(svg);
}
